import { useState, useEffect } from 'react';

/**
 * Custom hook simulating a steady WebSocket stream of simulated agent telemtry.
 */
export function useWebSocket(url: string) {
    const [data, setData] = useState<any>(null);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        // Mocking websocket connection for hackathon frontend demo without running backend
        setIsConnected(true);
        let interval: any;

        const fetchData = async () => {
            try {
                // Dynamically fetch from the generated demo_data.json
                const response = await fetch('/demo_data.json');
                const json = await response.json();

                // Simulate streaming by randomly varying the data slightly
                const liveData = {
                    ...json,
                    current_metrics: {
                        active_agents: 5 + Math.floor(Math.random() * 3),
                        db_load: 65 + Math.floor(Math.random() * 10),
                        cost_savings_usd: 1200 + Math.floor(Math.random() * 50)
                    }
                };
                setData(liveData);
            } catch (e) {
                console.error("Failed fetching mock stream", e);
            }
        };

        fetchData();
        interval = setInterval(fetchData, 2000);

        return () => {
            clearInterval(interval);
            setIsConnected(false);
        };
    }, [url]);

    return { data, isConnected };
}
